// ─── Chunking por estructura lógica (no por tamaño fijo) ─────────────────
// Respetar separadores naturales del documento evita cortar títulos y
// procedimientos a la mitad, lo que genera alucinaciones en el RAG.

const text       = $input.first().json.text || $input.first().json.data || '';
const sourceFile = $('📁 Google Drive — Nuevo Archivo').first().json.name || 'desconocido';
const sourceId   = $('📁 Google Drive — Nuevo Archivo').first().json.id   || '';

// Limpieza: normalizar saltos de línea y espacios extra
const cleaned = text
  .replace(/\r\n/g, '\n')
  .replace(/\n{4,}/g, '\n\n\n')
  .replace(/[ \t]{2,}/g, ' ')
  .trim();

const MAX_TOKENS  = 500;
const OVERLAP     = 50;
const SEPARADORES = ['\n\n\n', '\n\n', '\n', '. '];

function contarTokens(texto) {
  return Math.ceil(texto.split(/\s+/).length / 0.75);
}

function dividirPorSeparador(texto, separadores) {
  for (const sep of separadores) {
    const partes = texto.split(sep).filter(p => p.trim().length > 0);
    if (partes.length > 1) return partes;
  }
  return [texto];
}

function crearChunks(texto) {
  const secciones = dividirPorSeparador(texto, SEPARADORES);
  const chunks    = [];
  let   buffer    = '';
  let   overlap   = '';

  for (const seccion of secciones) {
    const candidato = overlap + (buffer ? '\n\n' + seccion : seccion);
    if (contarTokens(candidato) <= MAX_TOKENS) {
      buffer = candidato;
    } else {
      if (buffer.trim()) {
        chunks.push(buffer.trim());
        const palabras = buffer.split(/\s+/);
        overlap = palabras.slice(-OVERLAP).join(' ');
      }
      buffer  = overlap + '\n\n' + seccion;
      overlap = '';
    }
  }
  if (buffer.trim()) chunks.push(buffer.trim());
  return chunks;
}

const chunks = crearChunks(cleaned);

return chunks
  .filter(chunk => chunk.trim().length > 50)
  .map((chunk, index) => ({
    json: {
      chunk_text:   chunk,
      chunk_index:  index,
      source_file:  sourceFile,
      source_id:    sourceId,
      total_chunks: chunks.length,
      tokens_aprox: contarTokens(chunk),
      created_at:   new Date().toISOString()
    }
  }));

const embeddingData = $input.first().json;
const embedding     = embeddingData.embedding || [];
const chunk         = $('🧹 Limpiar y Dividir en Chunks').first().json;

return [{
  json: {
    content:   chunk.chunk_text,
    embedding: embedding,
    metadata: {
      source_file:  chunk.source_file,
      source_id:    chunk.source_id,
      chunk_index:  chunk.chunk_index,
      total_chunks: chunk.total_chunks,
      tokens_aprox: chunk.tokens_aprox
    },
    created_at: chunk.created_at
  }
}];
